manifest_content:
{
  "name": "design-monorepo",
  "private": true,
  "workspaces": [
    "packages/*"
  ],
  "packageManager": "bun@1.3.9",
  "scripts": {
    "build": "turbo build",
    "test": "turbo test",
    "lint": "turbo lint",
    "cli": "bun run packages/cli/src/index.ts"
  },
  "devDependencies": {
    "@types/node": "^25.6.0",
    "bun-types": "^1.3.12",
    "turbo": "latest",
    "typescript": "latest"
  }
}

[workspace]
members = ["crates/*"]
resolver = "2"

[workspace.package]
# Please update rustfmt.toml when bumping the Rust edition
edition = "2024"
rust-version = "1.94"
homepage = "https://docs.astral.sh/ruff"
documentation = "https://docs.astral.sh/ruff"
repository = "https://github.com/astral-sh/ruff"
authors = ["Charlie Marsh <charlie.r.marsh@gmail.com>"]
license = "MIT"

[workspace.dependencies]
ruff = { version = "0.15.20", path = "crates/ruff" }
ruff_annotate_snippets = { version = "0.0.3", path = "crates/ruff_annotate_snippets" }
ruff_cache = { version = "0.0.3", path = "crates/ruff_cache" }
ruff_db = { version = "0.0.3", path = "crates/ruff_db", default-features = false }
ruff_diagnostics = { version = "0.0.3", path = "crates/ruff_diagnostics" }
ruff_formatter = { version = "0.0.3", path = "crates/ruff_formatter" }
ruff_graph = { version = "0.0.3", path = "crates/ruff_graph" }
ruff_index = { version = "0.0.3", path = "crates/ruff_index" }
ruff_linter = { version = "0.15.20", path = "crates/ruff_linter" }
ruff_macros = { version = "0.0.3", path = "crates/ruff_macros" }
ruff_markdown = { version = "0.0.3", path = "crates/ruff_markdown" }
ruff_memory_usage = { version = "0.0.3", path = "crates/ruff_memory_usage" }
ruff_notebook = { version = "0.0.3", path = "crates/ruff_notebook" }
ruff_options_metadata = { version = "0.0.3", path = "crates/ruff_options_metadata" }
ruff_python_ast = { version = "0.0.3", path = "crates/ruff_python_ast" }
ruff_python_codegen = { version = "0.0.3", path = "crates/ruff_python_codegen" }
ruff_python_formatter = { version = "0.0.3", path = "crates/ruff_python_formatter" }
ruff_python_importer = { version = "0.0.3", path = "crates/ruff_python_importer" }
ruff_python_index = { version = "0.0.3", path = "crates/ruff_python_index" }
ruff_python_literal = { version = "0.0.3", path = "crates/ruff_python_literal" }
ruff_python_parser = { version = "0.0.3", path = "crates/ruff_python_parser" }
ruff_python_semantic = { version = "0.0.3", path = "crates/ruff_python_semantic" }
ruff_python_stdlib = { version = "0.0.3", path = "crates/ruff_python_stdlib" }
ruff_python_trivia = { version = "0.0.3", path = "crates/ruff_python_trivia" }
ruff_server = { version = "0.0.3", path = "crates/ruff_server" }
ruff_source_file = { version = "0.0.3", path = "crates/ruff_source_file" }
ruff_mdtest = { path = "crates/ruff_mdtest" }
ruff_ranged_value = { version = "0.0.2", path = "crates/ruff_ranged_value" }
ruff_text_size = { version = "0.0.3", path = "crates/ruff_text_size" }
ruff_workspace = { version = "0.0.3", path = "crates/ruff_workspace" }

ty = { path = "crates/ty" }
ty_combine = { version = "0.0.2", path = "crates/ty_combine" }
ty_completion_bench = { path = "crates/ty_completion_bench" }
ty_completion_eval = { path = "crates/ty_completion_eval" }
ty_ide = { path = "crates/ty_ide" }
ty_module_resolver = { version = "0.0.3", path = "crates/ty_module_resolver" }
ty_project = { path = "crates/ty_project", default-features = false }
ty_python_semantic = { version = "0.0.2", path = "crates/ty_python_semantic" }
ty_python_core = { version = "0.0.2", path = "crates/ty_python_core" }
ty_server = { path = "crates/ty_server" }
ty_site_packages = { version = "0.0.3", path = "crates/ty_site_packages" }
ty_static = { version = "0.0.3", path = "crates/ty_static" }
ty_test = { path = "crates/ty_test" }
ty_vendored = { version = "0.0.2", path = "crates/ty_vendored" }

mdtest = { path = "crates/mdtest" }

aho-corasick = { version = "1.1.3" }
arrayvec = { version = "0.7.6" }
anstream = { version = "1.0.0" }
anstyle = { version = "1.0.10" }
anyhow = { version = "1.0.80" }
arc-swap = { version = "1.7.1" }
argfile = { version = "1.0.0" }
assert_fs = { version = "1.1.0" }
rkyv = { version = "0.8.16" }
bitflags = { version = "2.5.0" }
bitvec = { version = "1.0.1", default-features = false, features = [
    "alloc",
] }
bstr = { version = "1.9.1" }
cachedir = { version = "0.3.1" }
camino = { version = "1.1.7" }
clap = { version = "4.5.3", features = ["derive"] }
clap_complete_command = { version = "0.6.0" }
clearscreen = { version = "4.0.0" }
codspeed-criterion-compat = { version = "4.4.1", default-features = false }
colored = { version = "3.0.0" }
compact_str = "0.9.0"
console_error_panic_hook = { version = "0.1.7" }
console_log = { version = "1.0.0" }
countme = { version = "3.0.1" }
criterion = { version = "0.8.0", default-features = false }
crossbeam = { version = "0.8.4" }
csv = { version = "1.3.1" }
dashmap = { version = "6.0.1" }
datatest-stable = { version = "0.3.3" }
divan = { package = "codspeed-divan-compat", version = "4.4.1" }
drop_bomb = { version = "0.1.5" }
dunce = { version = "1.0.5" }
etcetera = { version = "0.11.0" }
fern = { version = "0.7.0" }
filetime = { version = "0.2.23" }
get-size2 = { version = "0.10.0", features = [
    "derive",
    "smallvec",
    "hashbrown",
    "compact-str",
    "ordermap",
    "thin-vec",
] }
glob = { version = "0.3.1" }
globset = { version = "0.4.14" }
globwalk = {
